// Vincula la respuesta del usuario con su transcripción y prepara el texto para Haiku.
// Si 'Buscar hilo' devolvió 0 filas, este nodo no se ejecuta (la respuesta no era a un resumen).
const vinculo = $json; // transcripcion_id, cliente_id
const correo = $('Gmail Trigger').first().json;

// Cuerpo del correo (texto plano preferido)
let cuerpo = correo.text || correo.textPlain || correo.snippet || '';

// Quita la cita del correo original (sin regex): líneas '>' y todo lo posterior a "... escribió:" / "... wrote:"
const out = [];
for (const l of String(cuerpo).split('\n')) {
  const t = l.trim();
  if (t.startsWith('>')) continue;
  if (t.endsWith('escribió:') || t.endsWith('wrote:')) break;
  out.push(l);
}
// ponytail: heurística simple de strip de cita; si tu cliente usa otro separador, amplía la condición.
cuerpo = out.join('\n').trim();

// Autor (email del que corrige)
let autor = '';
if (correo.from && correo.from.value && correo.from.value[0]) autor = correo.from.value[0].address;
else autor = correo.from || '';

const system_prompt = [
'Eres un extractor de correcciones para un sistema de inteligencia de reuniones del sector agrícola (semillas).',
'El usuario responde por correo a un resumen para corregir errores de transcripción, sobre todo en NOMBRES PROPIOS: personas/agricultores, variedades de semilla y sitios/fincas.',
'',
'Tu única tarea: leer el texto del usuario y devolver las correcciones en JSON estricto.',
'',
'Reglas:',
'- Devuelve EXCLUSIVAMENTE un array JSON. Nada de texto antes o después, sin explicaciones, sin markdown.',
'- Cada elemento: {"texto_erroneo": string, "texto_correcto": string, "tipo": "persona"|"variedad"|"sitio"|"otro"}.',
'- Puede haber varias correcciones en un mismo correo: inclúyelas todas.',
'- "texto_erroneo" es la forma equivocada tal como aparece en la transcripción; "texto_correcto" es la forma correcta que indica el usuario.',
'- No inventes correcciones que el usuario no pide.',
'- Si no hay ninguna corrección clara, devuelve [].',
'',
'Ejemplo de entrada: donde pone Martínez es Benítez, y la variedad era Lamuyo no Lamayo',
'Salida: [{"texto_erroneo":"Martínez","texto_correcto":"Benítez","tipo":"persona"},{"texto_erroneo":"Lamayo","texto_correcto":"Lamuyo","tipo":"variedad"}]'
].join('\n');

return [{ json: {
  transcripcion_id: vinculo.transcripcion_id,
  cliente_id: vinculo.cliente_id,
  autor: autor,
  texto_usuario: cuerpo,
  system_prompt: system_prompt
} }];

// Parsea la salida JSON de Haiku. Devuelve UN ítem con la lista de correcciones + metadatos.
const resp = $json;
const prep = $('Preparar').first().json;
const trig = $('Gmail Trigger').first().json;
let texto = (resp.content && resp.content[0] && resp.content[0].text) ? resp.content[0].text : '[]';
texto = texto.replace('```json', '').replace('```', '').trim();
let arr = [];
try { arr = JSON.parse(texto); } catch (e) { arr = []; }
if (!Array.isArray(arr)) arr = [];
const correcciones = arr.filter(c => c && c.texto_erroneo && c.texto_correcto).map(c => ({
  texto_erroneo: String(c.texto_erroneo).trim(),
  texto_correcto: String(c.texto_correcto).trim(),
  tipo: c.tipo || 'otro'
}));
return [{ json: {
  transcripcion_id: prep.transcripcion_id,
  cliente_id: prep.cliente_id,
  autor: prep.autor,
  threadId: trig.threadId,
  messageId: trig.id,
  correcciones: correcciones,
  n: correcciones.length
} }];

// Expande la lista a N ítems (0 si no hubo correcciones) para insertarlas.
const base = $json;
return (base.correcciones || []).map(c => ({ json: {
  transcripcion_id: base.transcripcion_id,
  cliente_id: base.cliente_id,
  autor: base.autor,
  texto_erroneo: c.texto_erroneo,
  texto_correcto: c.texto_correcto,
  tipo: c.tipo
} }));

