// Mensaje de acuse según haya o no correcciones. Siempre 1 ítem -> el usuario siempre sabe que su respuesta llegó.
const j = $json;
const mensaje = j.n > 0
  ? 'Añadido a correcciones.'
  : 'He recibido tu mensaje pero no he identificado ninguna corrección clara. Si quieres corregir algo, indícamelo así: «donde pone X es Y».';
return [{ json: { messageId: j.messageId, mensaje: mensaje } }];
